3	/** Create a tiny mutable runtime slot with strict access when the runtime has not been initialized. */
4	export function createPluginRuntimeStore<T>(errorMessage: string): {
5	  setRuntime: (next: T) => void;
6	  clearRuntime: () => void;
7	  tryGetRuntime: () => T | null;
8	  getRuntime: () => T;
9	} {
10	  let runtime: T | null = null;
11	
12	  return {
13	    setRuntime(next: T) {
14	      runtime = next;
15	    },
16	    clearRuntime() {
17	      runtime = null;
18	    },
19	    tryGetRuntime() {
20	      return runtime;
21	    },
22	    getRuntime() {
23	      if (!runtime) {
24	        throw new Error(errorMessage);
25	      }
26	      return runtime;
27	    },
28	  };
29	}
