      "stageRuntimeDependencies": true
    }
  }
}
```

**Key openclaw block fields:**
- `extensions`: array of entry files for the plugin
- `setupEntry`: entry point for setup UI/wizard
- `channel`: channel definition with metadata (id, labels, docs, capabilities)
- `bundle.stageRuntimeDependencies`: stages dependencies for bundling

---

### 2. **Plugin Manifest** (`openclaw.plugin.json`)

**Location:** `/extensions/telegram/openclaw.plugin.json`

```json
{
  "id": "telegram",
  "channels": ["telegram"],
  "configSchema": {
    "type": "object",
    "additionalProperties": false,
    "properties": {}
  }
}
```

**Fields:**
- `id`: unique plugin identifier
- `channels`: array of channel IDs this plugin provides
- `configSchema`: JSON schema for plugin configuration (empty in this case; channel-level config is handled separately via `TelegramChannelConfigSchema`)

---

### 3. **Main Entry Point** (`index.ts`)

**Location:** `/extensions/telegram/index.ts`

```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { telegramPlugin } from "./src/channel.js";
import { setTelegramRuntime } from "./src/runtime.js";

