  config: TelegramAccountConfig;
};
```

**Account Resolution Functions:**
- `resolveTelegramAccount(params: { cfg: OpenClawConfig; accountId?: string | null }): ResolvedTelegramAccount`
- `listTelegramAccountIds(cfg: OpenClawConfig): string[]`
- `resolveDefaultTelegramAccountId(cfg: OpenClawConfig): string`
- `listEnabledTelegramAccounts(cfg: OpenClawConfig): ResolvedTelegramAccount[]`

**Token Resolution:**
- Sources: `env` (environment variable), `tokenFile` (file path), `config` (inline in config), `none` (no token)
- Supports multi-account setups with account-specific fallback

---

