### 8. **Outbound Adapter Details** (`src/outbound-adapter.ts`)

**Location:** `/extensions/telegram/src/outbound-adapter.ts`

```typescript
export const TELEGRAM_TEXT_CHUNK_LIMIT = 4000;

type TelegramSendFn = typeof sendMessageTelegram;
type TelegramSendOpts = Parameters<TelegramSendFn>[2];

export async function sendTelegramPayloadMessages(params: {
  send: TelegramSendFn;
  to: string;
  payload: ReplyPayload;
  baseOpts: Omit<NonNullable<TelegramSendOpts>, "buttons" | "mediaUrl" | "quoteText">;
}): Promise<Awaited<ReturnType<TelegramSendFn>>>;

export const telegramOutbound: ChannelOutboundAdapter = {
  deliveryMode: "direct",
  chunker: markdownToTelegramHtmlChunks,
  chunkerMode: "markdown",
  textChunkLimit: TELEGRAM_TEXT_CHUNK_LIMIT, // 4000
  shouldSkipPlainTextSanitization: ({ payload }) => Boolean(payload.channelData),
  resolveEffectiveTextChunkLimit: ({ fallbackLimit }) =>
    typeof fallbackLimit === "number" ? Math.min(fallbackLimit, 4096) : 4096,
  ...createAttachedChannelResultAdapter({
    channel: "telegram",
    sendText: async (ctx) => SendResult,
    sendMedia: async (ctx) => SendResult,
  }),
  sendPayload: async (ctx) => SendResult,
};
```

**Key Features:**
- Uses `createAttachedChannelResultAdapter` to attach channel ID to results
- Supports `channelData.telegram` for custom buttons and quote text
- Media support with fallback to text-only delivery
- HTML formatting for text chunks

