### 5. `extensions/pulseboard/src/channel.ts`

Pattern: `extensions/nostr/src/channel.ts` (simpler DM+group channel)

```typescript
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
      order: 100,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => [],
      resolveAccount: () => ({ accountId: "default" }),
      defaultAccountId: () => "default",
      isConfigured: () => false,
    },
    setup: {
      applyAccountConfig: async () => {},
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info("[pulseboard] connecting to PulseBoard...");
        return { stop: () => {} };
