185	/** Remove one of the known provider prefixes from a free-form target string. */
186	export function stripChannelTargetPrefix(raw: string, ...providers: string[]): string {
187	  const trimmed = raw.trim();
188	  for (const provider of providers) {
189	    const prefix = `${provider.toLowerCase()}:`;
190	    if (trimmed.toLowerCase().startsWith(prefix)) {
191	      return trimmed.slice(prefix.length).trim();
192	    }
193	  }
194	  return trimmed;
195	}
