293	/**
294	 * Canonical entry helper for channel plugins.
295	 *
296	 * This wraps `definePluginEntry(...)`, registers the channel capability, and
297	 * optionally exposes extra full-runtime registration such as tools or gateway
298	 * handlers that only make sense outside setup-only registration modes.
299	 */
300	export function defineChannelPluginEntry<TPlugin>({
301	  id,
302	  name,
303	  description,
304	  plugin,
305	  configSchema = emptyPluginConfigSchema,
306	  setRuntime,
307	  registerCliMetadata,
308	  registerFull,
309	}: DefineChannelPluginEntryOptions<TPlugin>): DefinedChannelPluginEntry<TPlugin> {
310	  const resolvedConfigSchema = typeof configSchema === "function" ? configSchema() : configSchema;
311	  const entry = {
312	    id,
313	    name,
314	    description,
315	    configSchema: resolvedConfigSchema,
316	    register(api: OpenClawPluginApi) {
317	      if (api.registrationMode === "cli-metadata") {
318	        registerCliMetadata?.(api);
319	        return;
320	      }
321	      setRuntime?.(api.runtime);
322	      api.registerChannel({ plugin: plugin as ChannelPlugin });
323	      if (api.registrationMode !== "full") {
324	        return;
325	      }
326	      registerCliMetadata?.(api);
327	      registerFull?.(api);
328	    },
329	  };
330	  return {
331	    ...entry,
332	    channelPlugin: plugin,
333	    ...(setRuntime ? { setChannelRuntime: setRuntime } : {}),
334	  };
335	}
