export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging via PulseBoard.",
      order: 100,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => ["default"],
      resolveAccount: (_cfg, accountId) => ({
        accountId: accountId ?? "default",
        enabled: true,
        configured: false,
      }),
      isConfigured: (account) => account.configured,
      describeAccount: (account) => ({
        accountId: account.accountId,
        configured: account.configured,
      }),
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[${ctx.account.accountId}] PulseBoard channel connected (stub)`);
        return {
          stop: () => {
            ctx.log?.info(`[${ctx.account.accountId}] PulseBoard channel disconnected`);
          },
        };
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => ({
      channel: "pulseboard",
      to,
      messageId: `pb-${Date.now()}`,
    }),
  },
});

